178	// DefaultProfileLadders returns the built-in profile escalation policy.
179	func DefaultProfileLadders() map[string][]string {
180		out := make(map[string][]string, len(defaultProfileLadders))
181		for profile, ladder := range defaultProfileLadders {
182			out[profile] = append([]string(nil), ladder...)
183		}
184		return out
185	}
